{"code": "import json, re
from collections import Counter, defaultdict

# Get the data from storage properly
biz_data = locals()['var_functions.query_db:66']
rev_data = locals()['var_functions.query_db:62']

# If they are file paths, read them; if they are lists, use them directly
if isinstance(biz_data, str) and '.json' in biz_data:
    with open(biz_data) as f:
        businesses = json.load(f)
else:
    businesses = biz_data

if isinstance(rev_data, str) and '.json' in rev_data:
    with open(rev_data) as f:
        reviews = json.load(f)
else:
    reviews = rev_data

# Map reviews by business_ref
review_ratings = defaultdict(list)
for r in reviews:
    try:
        rating = int(r['rating'])
        ref = r['business_ref']
        review_ratings[ref].append(rating)
    except Exception:
        continue

# Process businesses with credit cards
category_counts = Counter()
biz_to_categories = {}
biz_to_ref = {}

for biz in businesses:
    attrs = biz.get('attributes', {})
    if not isinstance(attrs, dict) or attrs.get('BusinessAcceptsCreditCards') != 'True':
        continue
    biz_id = biz['business_id']
    desc = biz.get('description', '')
    # Create ref mapping
    ref = biz_id.replace('businessid_', 'businessref_')
    biz_to_ref[biz_id] = ref

    # Extract categories - look for capitalized words/lists
    cats = []
    # Find text after "in", "including", "fields of"
    m = re.search(r"(?:in|including|fields of)\s+([A-Z][^\.]+)", desc, re.I)
    if m:
        txt = m.group(1).strip()
        # Split by comma or 'and'
        for p in re.split(r',\s*|\s+and\s+', txt):
            p = p.strip().rstrip(".').")
            # Remove leading words
            p = re.sub(r"^(in|of|including|and)\s+", "", p, flags=re.I).strip()
            if p and len(p) > 2 and 'Located at' not in p:
                cats.append(p)
    if cats:
        biz_to_categories[biz_id] = cats
        for c in cats:
            category_counts[c] += 1

if not category_counts:
    print("__RESULT__:")
    print(json.dumps({"error": "No categories found"}))
else:
    top_category, top_n = category_counts.most_common(1)[0]
    # Get ratings for businesses in this category
    ratings = []
    for biz_id, cats in biz_to_categories.items():
        if top_category in cats:
            ref = biz_to_ref[biz_id]
            if ref in review_ratings:
                ratings.extend(review_ratings[ref])

    avg = sum(ratings)/len(ratings) if ratings else None
    result = {
        "top_category": top_category,
        "num_businesses": top_n,
        "average_rating": round(avg, 2) if avg is not None else None,
        "num_reviews": len(ratings)
    }
    print("__RESULT__:")
    print(json.dumps(result))
"}
